function projectAuditorCompactLinesV1(a=projectAuditorStateV1()){return[`- project auditor v1: active read-only repo audit ✅`,`- project auditor commands: /project_audit /project_audit_file`,`- project auditor GitHub write: ${a.github_write} ✅`,`- project auditor proposal/apply: ${a.proposal_create}/${a.apply} ✅`,`- project auditor secrets output: none ✅`]}
function projectAuditSecretLikePath(path){return/(^|\/)(\.env|\.env\.|.*secret.*|.*token.*|.*password.*|.*passwd.*|.*credential.*|.*private.*|.*\.pem|.*\.key)$/i.test(String(path||""))}
function projectAuditImportant(item,activePath){const p=item.path||"";return p===activePath||p==="cloudflare/wrangler.toml"||p==="package.json"||p==="package-lock.json"||p.endsWith("smoke.yml")||p.includes(".github/workflows")||p.toLowerCase().includes("readme")||p==="cloudflare"||p==="cloudflare/src"}
function projectAuditRiskForFile(path,cls={}){const p=String(path||"");if(projectAuditSecretLikePath(p))return{risk:"blocked",reason:"secret-like path; content must not be exposed"};if(p==="cloudflare/wrangler.toml")return{risk:"critical",reason:"worker config protected"};if(cls.kind==="protected")return{risk:"critical",reason:cls.reason||"protected active file"};if(p.startsWith(".github/"))return{risk:"high",reason:"CI/workflow config"};if(p.endsWith(".js")&&p.startsWith("cloudflare/src/"))return{risk:"medium",reason:"worker/runtime JS; review before edits"};return{risk:cls.risk||"low",reason:cls.reason||"metadata/read-only"}}
function projectAuditPushRows(lines,title,items,limit=12){lines.push(`${title}: ${items.length}`);if(!items.length){lines.push("- none");return}for(const x of items.slice(0,limit)){const sha=x.sha?` sha=${String(x.sha).slice(0,10)}`:"";lines.push(`- ${x.path}${sha} risk=${x.risk||"low"} reason=${x.reason||"—"}`)}if(items.length>limit)lines.push(`- ... +${items.length-limit} more`)}
