function llmIntentHardSafetyBlockV1(text){const t=String(text||"").trim().toLowerCase();if(!t)return null;if(/^(да|yes|y|ок|okay|подтверждаю|применяй|apply|go|го|делай)$/i.test(t))return{intent:"blocked_dangerous",user_meaning:"Короткое подтверждение без явной slash-команды",target:"unknown",risk:"high_guarded_action",tool:"none",args:"",can_execute:false,requires_confirmation:true,requires_explicit_command:"explicit slash safety command",response_text:"Я поняла, но обычным «да/ок/применяй» я ничего не применяю и не меняю. Для опасных действий нужны явные slash-команды safety-ядра.",confidence:100};if(/\/apply_confirm|\/cleanup_delete_confirm|\/confirm_rollback|wrangler\.toml|секрет|token|deploy|удали файл|delete file/i.test(t)&&!t.startsWith("/"))return{intent:"blocked_dangerous",user_meaning:"Опасное действие запрошено обычным текстом",target:"guarded_action",risk:"high_guarded_action",tool:"none",args:"",can_execute:false,requires_confirmation:true,requires_explicit_command:"explicit slash safety command",response_text:"Я понял опасное действие, но обычным текстом это не выполняю. Для GitHub/apply/deploy/delete/secrets остаются только явные slash-команды и старые safety gates.",confidence:100};return null}
async function llmIntentCallV1(env,c,userText){if(!c.openrouter)throw new Error("OPENROUTER_API_KEY missing for Jarvis Agent Runtime v1");const budget=await costBeforeThink(env);if(!budget.ok)throw new Error("cost guard blocked Jarvis Agent Runtime: "+budget.message.replace(/\n/g," | "));const pack=await jarvisContextPackV1(env,c);const system=["Ты Jarvis Agent Runtime v1 внутри MiniSkynet Сергея.","Ты не обычный ChatGPT. Ты Лондон: личный инженерный агент Сергея. Всегда отвечай по-русски, живо, коротко и по делу.","Твоя задача — понять любой обычный текст Сергея и вернуть СТРОГО один JSON без markdown.","Не используй шаблоны фраз. Понимай смысл, объект, риск, инструмент и следующий безопасный шаг.","Доступные intent: status, project_state, briefing, tasks_show, next, memory_status, memory_search, memory_preview, capability_gap_check, improvement_card_create, task_close, task_add, task_add_next_backlog, improvement_suggest, self_code_inspect, followup_execute_last, general_answer, blocked_dangerous, unknown.","risk: read_only | low_risk_mutation | high_guarded_action.","Tool registry: task.list, task.add, task.add_next_backlog, task.close, project.status, memory.inspect, memory.search, memory.preview, capability.check, improvement.card, self.code.inspect, chat.answer.","Если Сергей просит показать задачи/что активно — intent tasks_show.","Если Сергей просит добавить следующую задачу по списку/backlog/плану — intent task_add_next_backlog, target clean_backlog_next.","Если Сергей пишет Добавляй/делай/окей после твоего предложения — intent followup_execute_last, если last_action существует. Это не apply_confirm.","Если Сергей просит посмотреть свой код/как ты устроена/прочитай свой файл — intent self_code_inspect, risk read_only. Self Code Inspector v1 уже доступен: можно показать read-only карту активного index-v4.js или поиск по символам.","Если Сергей просит предложить улучшение — intent improvement_suggest. Используй clean_backlog_next или obvious missing capability.","Если просьба требует отсутствующую capability — используй capability_gap_check или improvement_card_create.","Для task_close ты НЕ выбираешь имя задачи. Только target active_task_only, task_index:N, task_id:ID, all_active_tasks или ambiguous.","Если активная задача ровно одна и смысл — закрыть текущую/эту/активную задачу, target active_task_only.","Если несколько задач и цель неясна — target ambiguous, can_execute false.","GitHub/apply/deploy/delete/secrets/wrangler.toml/cleanup confirm/rollback confirm — high_guarded_action, can_execute false, requires_explicit_command slash safety command.","Никогда не пиши generic English. Если capability missing — скажи это по-русски как Лондон.","response_text — короткий живой русский ответ, который можно показать Сергею.","Верни JSON: {\"intent\":\"...\",\"user_meaning\":\"...\",\"target\":\"...\",\"target_text\":\"...\",\"risk\":\"...\",\"tool\":\"...\",\"args\":\"...\",\"can_execute\":true,\"requires_confirmation\":false,\"requires_explicit_command\":\"\",\"response_text\":\"...\",\"confidence\":0}"].join("\n");const context=jarvisContextTextV1(pack);const r=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{"content-type":"application/json",authorization:`Bearer ${c.openrouter}`},body:JSON.stringify({model:c.model,messages:[{role:"system",content:system},{role:"user",content:`AGENT CONTEXT PACK:\n${context}\n\nUSER TEXT:\n${userText}`}],max_tokens:COST_MAX_TOKENS,temperature:0.12,response_format:{type:"json_object"}})});const data=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`OpenRouter intent error ${r.status}: ${data?.error?.message||"request failed"}`);const raw=data?.choices?.[0]?.message?.content||"{}";const parsed=llmIntentExtractJsonV1(raw);if(!parsed)throw new Error("LLM returned non-JSON intent frame");return llmIntentNormalizeV1(parsed)}
function llmIntentFrameTextV1(frame,executed="preview",extra=""){return["🧠 Jarvis Intent Frame v1",`mode: ${JARVIS_AGENT_RUNTIME_V1.mode}`,"KV write: none in preview ✅","GitHub write from natural text: none ✅","proposal/apply from natural text: none/none ✅","auto-apply: disabled ✅",`intent: ${frame.intent}`,`meaning: ${frame.user_meaning||"—"}`,`target: ${frame.target||"—"}`,`target_text: ${frame.target_text||"—"}`,`risk: ${frame.risk}`,`tool: ${frame.tool||"none"}`,`args: ${clip(frame.args||"",300)}`,`can_execute: ${frame.can_execute?"yes":"no"}`,`requires_confirmation: ${frame.requires_confirmation?"yes":"no"}`,`requires_explicit_command: ${frame.requires_explicit_command||"none"}`,`confidence: ${frame.confidence}/100`,`gate: ${executed}`,extra?`note: ${extra}`:"",frame.response_text?`response_text:\n${frame.response_text}`:""].filter(Boolean).join("\n")}
async function llmIntentPreviewTextV1(env,c,args=""){const hard=llmIntentHardSafetyBlockV1(args);const frame=hard||await llmIntentCallV1(env,c,args);return llmIntentFrameTextV1(frame,"preview_only","no action executed")}
async function llmIntentExecuteReadOnlyV1(env,c,m,cmd,args){return handle(env,c,{...m,command:cmd,args:args||"",text:[cmd,args].filter(Boolean).join(" ")})}
function llmIntentTargetIndexV1(frame){const raw=String([frame.target,frame.args].filter(Boolean).join(" ")).trim();const m=raw.match(/(?:^|\b)(?:task_index|index|номер|n)\s*[:=#-]?\s*(\d{1,2})(?:\b|$)/i)||raw.match(/^\s*(\d{1,2})\s*$/);return m?Math.max(0,parseInt(m[1],10)-1):null}
function llmIntentTargetIdV1(frame){const raw=String([frame.target,frame.args].filter(Boolean).join(" ")).trim();const m=raw.match(/(?:task_id|id)\s*[:=#-]?\s*([a-zA-Z0-9_-]{3,80})/i);return m?m[1]:""}
function llmIntentTargetModeV1(frame){const t=String(frame.target||"").toLowerCase().trim();if(t==="active_task_only"||t==="only_active_task")return"active_task_only";if(t==="all_active_tasks")return"all_active_tasks";if(t==="ambiguous"||t==="unknown")return"ambiguous";if(/^task_index/i.test(t))return"task_index";if(/^task_id/i.test(t))return"task_id";return"ambiguous"}
async function llmIntentDispatchV1(env,c,m){const text=String(m.text||"").trim();if(!text||text.startsWith("/"))return null;let frame;try{frame=llmIntentHardSafetyBlockV1(text)||await llmIntentCallV1(env,c,text)}catch(e){return send(c,m.chatId,["Серёга, мой Jarvis-мозг не ответил нормально.",`Ошибка: ${clip(e.message||e,500)}`,"Ничего не выполнила. Slash-команды остаются запасным управлением."].join("\n"))}
  if(frame.risk==="high_guarded_action"||frame.intent==="blocked_dangerous")return send(c,m.chatId,[jarvisResponseRussianV1(frame,"Я поняла опасное действие, но обычным текстом его не выполняю."),`Нужна явная команда: ${frame.requires_explicit_command||"slash safety command"}`,"GitHub/apply/deploy/delete/secrets — только через safety gates. Auto-apply выключен."].join("\n"));
  if(frame.intent==="followup_execute_last")return jarvisExecuteLastActionV1(env,c,m);
  if(frame.intent==="tasks_show"){const tasks=await arr(env,"tasks"),active=tasks.filter(x=>x.status!=="done").slice(0,12);return send(c,m.chatId,jarvisHumanTaskListV1(active))}
  if(frame.intent==="task_add_next_backlog"){const target=frame.target_text||frame.args||"";const r=await jarvisAddBacklogTaskV1(env,c,target);return send(c,m.chatId,`Готово, Серёга. Добавила следующую задачу: ${r.target}.`)}
  if(frame.intent==="improvement_suggest"){const p=await jarvisContextPackV1(env,c);await jarvisSetLastActionV1(env,{type:"add_backlog_task",target:p.backlog_target,reason:"improvement_suggest"});return send(c,m.chatId,[`Я бы следующим улучшением взяла: ${p.backlog_target}.`,"Почему: это следующий clean-backlog слой после уже собранной цепочки memory → gap → card → intent.","Могу добавить задачу. Напиши: «добавляй»."].join("\n"))}
  if(frame.intent==="self_code_inspect")return send(c,m.chatId,await selfCodeHumanInspectV1(c,frame.args||frame.target_text||text));
  if(frame.intent==="capability_gap_check")return send(c,m.chatId,jarvisHumanCapabilityGapTextV1(frame.args||frame.target_text||text));
  if(frame.intent==="improvement_card_create")return send(c,m.chatId,jarvisHumanImprovementTextV1(frame.args||frame.target_text||text));
  const readOnlyMap={status:["/status",""],project_state:["/project_state",""],briefing:["/briefing",""],next:["/next",""],memory_status:["/memory_curator_status",""],memory_search:["/memory_search",frame.args||frame.target_text||text],memory_preview:["/memory_curator_preview",frame.args||frame.target_text||text]};
  if(readOnlyMap[frame.intent]){const [cmd,args]=readOnlyMap[frame.intent];return llmIntentExecuteReadOnlyV1(env,c,m,cmd,args)}
  if(frame.intent==="task_close"){const tasks=await arr(env,"tasks"),active=tasks.filter(x=>x.status!=="done");const mode=llmIntentTargetModeV1(frame),idx=llmIntentTargetIndexV1(frame),id=llmIntentTargetIdV1(frame);let chosen=[];if(active.length===1&&(mode==="active_task_only"||mode==="ambiguous"||mode==="all_active_tasks"))chosen=[active[0]];else if(mode==="task_index"&&idx!==null&&idx>=0&&idx<active.length)chosen=[active[idx]];else if(mode==="task_id"&&id)chosen=active.filter(t=>String(t.id)===String(id));else if(mode==="all_active_tasks"&&active.length>1){return send(c,m.chatId,["Я поняла, что речь про все активные задачи, но их несколько.","Массовое закрытие по обычному тексту не делаю, чтобы не снести лишнее.",...active.slice(0,8).map((t,i)=>`${i+1}. ${clip(t.text,160)}`),"Напиши конкретный номер или используй /task_done N."].join("\n"))}if(chosen.length){for(const task of chosen){task.status="done";task.done_at=now();task.done_source="jarvis_agent_runtime_v1"}await saveArr(env,"tasks",tasks,120);await jarvisClearLastActionV1(env);return send(c,m.chatId,["Готово, Серёга. Закрыла задачу:",...chosen.map(t=>`— ${clip(t.text,420)}`),"","GitHub/apply/deploy не трогала."].join("\n"))}return send(c,m.chatId,["Я поняла, что ты хочешь закрыть задачу, но локально не смогла точно выбрать цель.",`Активных задач: ${active.length}`,active.length?active.slice(0,8).map((t,i)=>`${i+1}. ${clip(t.text,160)}`).join("\n"):"Активных задач нет.","","Дай номер задачи или используй /task_done N."].join("\n"))}
  if(frame.intent==="task_add"){const taskText=String(frame.args||frame.target_text||"").trim();if(!taskText||frame.confidence<65){const p=await jarvisContextPackV1(env,c);await jarvisSetLastActionV1(env,{type:"add_backlog_task",target:p.backlog_target,reason:"unclear_task_add"});return send(c,m.chatId,[`Я могу добавить следующий clean-шаг: ${p.backlog_target}.`,`Если это оно — напиши «добавляй».`].join("\n"))}const task=await jarvisAddTaskV1(env,taskText,"jarvis_agent_runtime_v1:task_add");await jarvisClearLastActionV1(env);return send(c,m.chatId,`Готово, Серёга. Добавила задачу: ${task.text}`)}
  if((frame.intent==="general_answer"||frame.intent==="unknown")&&frame.response_text)return send(c,m.chatId,jarvisResponseRussianV1(frame,"Я поняла не до конца. Скажи, ты хочешь: добавить следующую задачу, проверить capability или создать карточку улучшения?"));
  return send(c,m.chatId,["Я поняла неуверенно, поэтому ничего не выполняю.",llmIntentFrameTextV1(frame,"blocked_by_uncertainty","уточни словами или используй slash-команду")].join("\n\n"))}


function memoryQuality(text){return memoryCuratorAnalyze(text).importance}
async function maybeRemember(env,userText,answer){const r=memoryCuratorAnalyze(userText);if(!r.save)return null;const mem=await arr(env,"memories"),norm=roadmapCleanText(r.summary);if(mem.some(x=>roadmapCleanText(x.text||"")===norm))return null;const item={id:uid("mem"),type:r.type,score:r.importance,text:r.summary,answer_hint:clip(answer,180),source:"memory_curator_v1",created_at:now()};mem.push(item);await saveArr(env,"memories",mem,500);await kvPut(env,"memory_curator:last",{saved:true,item_id:item.id,type:item.type,score:item.score,updated_at:now()});return item}
function utcDay(){return new Date().toISOString().slice(0,10)}
async function getCostState(env){const day=utcDay(),s=await kvGet(env,"cost:openrouter_daily",{date:day,requests:0,reserved_tokens:0,updated_at:now()});if(s.date!==day)return{date:day,requests:0,reserved_tokens:0,updated_at:now()};return{date:day,requests:Number(s.requests||0),reserved_tokens:Number(s.reserved_tokens||0),updated_at:s.updated_at||now()}}
async function putCostState(env,s){await kvPut(env,"cost:openrouter_daily",s)}
async function costBeforeThink(env){const s=await getCostState(env),reqLeft=COST_DAILY_REQUEST_LIMIT-s.requests,tokLeft=COST_DAILY_TOKEN_LIMIT-s.reserved_tokens;if(reqLeft<=0||tokLeft<COST_MAX_TOKENS)return{ok:false,state:s,message:["⛔ Cost Guard v1","OpenRouter budget exceeded. Запрос к модели не отправлен.",`date_utc: ${s.date}`,`requests: ${s.requests}/${COST_DAILY_REQUEST_LIMIT}`,`reserved_tokens: ${s.reserved_tokens}/${COST_DAILY_TOKEN_LIMIT}`,"next: дождаться UTC-сброса или поднять лимит вручную в коде."].join("\n")};s.requests+=1;s.reserved_tokens+=COST_MAX_TOKENS;s.updated_at=now();await putCostState(env,s);return{ok:true,state:s}}
async function costStatus(env){const s=await getCostState(env),reqLeft=Math.max(0,COST_DAILY_REQUEST_LIMIT-s.requests),tokLeft=Math.max(0,COST_DAILY_TOKEN_LIMIT-s.reserved_tokens);return["💸 Cost Status v1",`date_utc: ${s.date}`,`requests_used: ${s.requests}/${COST_DAILY_REQUEST_LIMIT}`,`requests_left: ${reqLeft}`,`max_tokens_per_think: ${COST_MAX_TOKENS}`,`reserved_tokens: ${s.reserved_tokens}/${COST_DAILY_TOKEN_LIMIT}`,`reserved_tokens_left: ${tokLeft}`,`reset: next UTC day`].join("\n")}

async function runThink(env,c,userText){if(!c.openrouter)return"⚠️ Think/dialog не включён: нет OPENROUTER_API_KEY.";const budget=await costBeforeThink(env);if(!budget.ok)return budget.message;const self=await getSelf(env),goals=await getGoals(env),plan=await getPlan(env),state=await projectStateSnapshot(env,c);const mem=(await arr(env,"memories")).slice(-8).map(m=>`- [${m.type||"note"}/${m.score||0}] ${m.text}`).join("\n")||"- пусто";const activeTasks=(await arr(env,"tasks")).filter(t=>t.status!=="done").slice(0,6).map(t=>`- ${t.text}`).join("\n")||"- нет";const system=["Ты MiniSkynet Core v5.6, облачная Лондон Сергея в Telegram.","Пиши по-русски, коротко, живо, на ты.","Твоя роль: личный инженерный агент. Не болталка.","PROJECT STATE — источник правды. Если legacy Plan конфликтует с Project State, верь Project State.","ROADMAP LOCK — главный порядок движения. Не предлагай Memory/Project Auditor/PC Bridge/Aurora audit, пока prerequisites не done.","AUTONOMOUS PLANNER v2 — если есть planner decision/action, считай это главным next step. FAILURE LOCK v1 — если active, не предлагай proposal/apply, сначала manual_review command.","AUTO PROPOSAL DRAFT v1 — draft это только текстовая рекомендация; proposal в KV не создаётся без ручного /propose.","APPLY GATE v2 — перед apply_confirm обязан быть fresh apply_check, sha match, no pending verify/live FAIL, capability/rollback ok.","MEMORY IMPORT PIPELINE v1 — импорт памяти только через preview → exact confirm; секреты/URL/tokens блокируют confirm.","MEMORY CURATOR v1 — важный диалог сжимается в typed memory; мусор не сохраняется.","CAPABILITY GAP DETECTOR v1 — если просьба требует отсутствующую capability, предложи /capability_gap_check и первый read-only шаг, без записи.","PROJECT AUDITOR v1 — аудит проекта только read-only: /project_audit и /project_audit_file; не пишет GitHub, не создаёт proposal/apply, не выводит секреты.","Не говори, что ничего не готово, если Project State показывает done/completed layers.","Не обещай запись в GitHub без /propose и /apply_check + /apply_confirm.","Если нужна правка кода — предложи одну безопасную следующую команду."].join("\n");const context=[`Self: ${self.text}`,`PROJECT STATE v1 (source of truth):\n${projectStateContext(state)}`,`Goals:\n${goals.goals.map((g,i)=>`${i+1}. ${g}`).join("\n")}`,`Legacy Plan (low priority, may be stale):\n${plan.steps.map((s,i)=>`${i+1}. ${s}`).join("\n")}`,`Active tasks from KV:\n${activeTasks}`,`Memory:\n${mem}`].join("\n\n");const r=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{"content-type":"application/json",authorization:`Bearer ${c.openrouter}`},body:JSON.stringify({model:c.model,messages:[{role:"system",content:system},{role:"user",content:`${context}\n\nСообщение Сергея:\n${userText}`}],max_tokens:COST_MAX_TOKENS,temperature:0.35})});const data=await r.json().catch(()=>({}));if(!r.ok)return`OpenRouter error ${r.status}: ${data?.error?.message||"request failed"}`;const answer=data?.choices?.[0]?.message?.content?.trim()||"Пустой ответ модели.";await maybeRemember(env,userText,answer);return answer}
function markerRange(src){const re=/const SELF_APPLY_MARKERS=\[([\s\S]*?)\];/m;const m=re.exec(src);if(!m)return null;return{start:m.index,end:m.index+m[0].length-2,block:m[0]}}
function hasMarker(src,marker){return String(src||"").includes(JSON.stringify(marker))}
function addMarker(src,marker){const r=markerRange(src);if(!r)throw new Error("SELF_APPLY_MARKERS block not found");if(hasMarker(src,marker))return{changed:false,content:src};return{changed:true,content:src.slice(0,r.end)+`,`+JSON.stringify(marker)+src.slice(r.end)}}
function markerFromRequest(req){let t=String(req||"").trim().replace(/^добавить\s+/i,"").replace(/^add\s+/i,"").replace(/\s+в\s+help$/i,"").replace(/\s+in\s+help$/i,"").trim();return(t||"custom marker").slice(0,90)}
