function watchdogLabel(age,status,state){if(status==="FAIL"||state==="live_failed")return"FAILED ❌";if(age===null)return"UNKNOWN ⚠️";if(age>=WATCHDOG_STALE_SEC)return"STALE ⛔";if(age>=WATCHDOG_EXPIRED_SEC)return"EXPIRED ⛔";if(age>=WATCHDOG_TIMEOUT_SEC)return"TIMEOUT ⚠️";return"PENDING ⏳"}
