async function readBlob(c,sha){if(!c.gh)throw new Error("GITHUB_TOKEN missing");const s=String(sha||"").trim();if(!/^[a-f0-9]{40}$/i.test(s))throw new Error("unsafe blob sha");const r=await fetch(`https://api.github.com/repos/${c.repo}/git/blobs/${s}`,{headers:{accept:"application/vnd.github+json","user-agent":"MiniSkynet-v517",authorization:`Bearer ${c.gh}`}});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub blob ${r.status}: ${d.message||"request failed"}`);if(d.encoding!=="base64")throw new Error("unsupported blob encoding");return b64d(d.content||"")}
